mapper.select:
SELECT topic_id, topic_name, category, result_form, max_capacity, status, create_time
FROM topic_library
WHERE category = #{category}
ORDER BY topic_id
LIMIT #{limit} OFFSET #{offset}

SELECT topic_id, topic_name, category, result_form, max_capacity, status, create_time
FROM topic_library
WHERE topic_id = #{topicId}

SELECT t.max_capacity - COALESCE(occ.occupied_cnt, 0) AS remaining
FROM topic_library t
LEFT JOIN (
    SELECT topic_id, COUNT(*) AS occupied_cnt
    FROM thesis_application
    WHERE application_status IN (1, 2, 3) AND topic_id = #{topicId}
    GROUP BY topic_id
) occ ON t.topic_id = occ.topic_id
WHERE t.topic_id = #{topicId}

mapper.update:
UPDATE topic_library
SET status = #{status}
WHERE topic_id = #{topicId}
